INSERT IGNORE INTO permissions (resource, action, description, is_system) VALUES ('strategies','read','View strategies',TRUE),('strategies','write','Create/update/delete strategies',TRUE),('strategies','manage','Manage strategy lifecycle',TRUE),('backtests','read','View backtest results',TRUE),('backtests','write','Submit/delete backtests',TRUE),('backtests','manage','Manage backtest jobs',TRUE),('trading','read','View orders and trades',TRUE),('trading','write','Place/modify/cancel orders',TRUE),('trading','manage','Manage trading operations',TRUE),('portfolios','read','View portfolio positions',TRUE),('portfolios','write','Modify portfolio holdings',TRUE),('portfolios','manage','Manage portfolio settings',TRUE),('reports','read','View reports and analytics',TRUE),('reports','write','Generate/customize reports',TRUE),('reports','manage','Manage report settings',TRUE),('data','read','View market data and watchlists',TRUE),('data','write','Create/modify watchlists',TRUE),('data','manage','Manage data sources',TRUE),('account','read','View own account info',TRUE),('account','write','Modify own account settings',TRUE),('account','manage','Manage user accounts',TRUE),('system','read','View system status/configs',TRUE),('system','write','Modify system configs',TRUE),('system','manage','Perform system operations',TRUE),('alerts','read','View alert rules and history',TRUE),('alerts','write','Create/modify/delete alerts',TRUE),('alerts','manage','Manage notification channels',TRUE),('collaboration','read','View shared resources',TRUE),('collaboration','write','Share strategies/comment',TRUE),('collaboration','manage','Manage workspace members',TRUE);
INSERT IGNORE INTO roles (name, description, is_system) VALUES ('admin','System administrator',TRUE),('trader','Active trader',TRUE),('researcher','Strategy researcher',TRUE),('viewer','Read-only user',TRUE);
INSERT IGNORE INTO role_permissions (role_id, permission_id) SELECT @admin_role_id, id FROM permissions;
INSERT IGNORE INTO role_permissions (role_id, permission_id) SELECT @trader_role_id, id FROM permissions WHERE resource IN ('strategies','backtests','trading','portfolios','reports','data','account','alerts') AND action IN ('read','write') UNION ALL SELECT @trader_role_id, id FROM permissions WHERE resource='trading' AND action='manage' UNION ALL SELECT @trader_role_id, id FROM permissions WHERE resource='account' AND action='manage' UNION ALL SELECT @trader_role_id, id FROM permissions WHERE resource='alerts' AND action='manage' UNION ALL SELECT @trader_role_id, id FROM permissions WHERE resource='data' AND action='manage';
INSERT IGNORE INTO role_permissions (role_id, permission_id) SELECT @researcher_role_id, id FROM permissions WHERE resource IN ('strategies','backtests','portfolios','reports','data','account') AND action IN ('read','write');
INSERT IGNORE INTO role_permissions (role_id, permission_id) SELECT @viewer_role_id, id FROM permissions WHERE resource IN ('reports','data','alerts','account') AND action='read';
